/**
 * Generate AgentMail firewall config.
 *
 * Data source: https://docs.agentmail.to/api-reference
 *
 * AgentMail is an email infrastructure platform for AI agents.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.agentmail.to/api-reference";
// Format: am_ + 32 hex chars (e.g. am_6064766aebe42477b7686ffd76374d68)
const PLACEHOLDER_VALUE = "am_c0ffee5afe10ca1c0ffee5afe10ca1c0";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from AgentMail API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:agentmail",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const agentmailFirewall = {",
    '  name: "agentmail",',
    '  description: "AgentMail API",',
    "  placeholders: {",
    `    AGENTMAIL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.agentmail.to",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.AGENTMAIL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating AgentMail firewall config...");
  const ts = generateTypeScript();
  writeOutput("agentmail", ts, import.meta.dirname);
}
